/**
 * System Design Icons - SVG icons for system architecture diagrams
 * Icons can be placed on canvas and scaled like other shapes
 */

export interface SystemIcon {
    id: string;
    name: string;
    category: IconCategory;
    svg: string; // SVG path data or full SVG element
    viewBox: string;
    defaultSize: number;
}

export type IconCategory =
    | 'database'
    | 'messaging'
    | 'cloud'
    | 'compute'
    | 'networking'
    | 'storage'
    | 'security'
    | 'other';

export const iconCategories: { id: IconCategory; label: string }[] = [
    { id: 'database', label: 'Databases' },
    { id: 'messaging', label: 'Messaging' },
    { id: 'cloud', label: 'Cloud' },
    { id: 'compute', label: 'Compute' },
    { id: 'networking', label: 'Networking' },
    { id: 'storage', label: 'Storage' },
    { id: 'security', label: 'Security' },
    { id: 'other', label: 'Other' },
];

