// Get icons by category
export function getIconsByCategory(category: IconCategory): SystemIcon[] {
    return systemIcons.filter(icon => icon.category === category);
}

// Get icon by ID
export function getIconById(id: string): SystemIcon | undefined {
    return systemIcons.find(icon => icon.id === id);
}

// Search icons by name
export function searchIcons(query: string): SystemIcon[] {
    const q = query.toLowerCase();
    return systemIcons.filter(icon =>
        icon.name.toLowerCase().includes(q) ||
        icon.category.toLowerCase().includes(q)
    );
}
